<template>
  <span v-if="searchPanel" class="ml-1 iSearchPanelWrap">
    <v-row class="align-center">
      <!-- <v-btn-toggle v-model="activeFilterBtn" multiple dense color="primary">
        <v-btn ref="gridFilterBtn" class="i-search-panel-button" @click="filterIconClick">
          <svg-icon icon-class="filter_line" />
        </v-btn>
      </v-btn-toggle> -->

      <!-- 검색 필터의 기능 중복으로 주석 -->
      <!-- <v-tooltip top color="condition_btn_bg">
        <template v-slot:activator="{ on, attrs }">
          <v-btn-toggle multiple dense color="condition_btn_bg">
            <v-btn outlined color="condition_btn_bg" class="i-search-panel-button" @click="HeaderfilterIconClick" v-bind="attrs" v-on="on">
              <svg-icon icon-class="filter_line" />
            </v-btn>
          </v-btn-toggle>
        </template>
        <span>헤더 필터</span>
      </v-tooltip> -->

      <v-tooltip top color="primary">
        <template v-slot:activator="{ on, attrs }">
          <v-btn-toggle multiple dense color="condition_btn_bg" class="mx-1">
            <v-btn
              outlined
              color="condition_btn_bg"
              ref="gridFilterBtn"
              class="i-search-panel-button"
              style="border-radius:4px !important;"
              @click="filterIconClick"
              v-bind="attrs"
              v-on="on"
            >
              <svg-icon style="color:#9BA4AC;" icon-class="grid_filter" />
            </v-btn>
          </v-btn-toggle>
        </template>
        <span>검색 필터</span>
      </v-tooltip>

      <v-tooltip top color="primary">
        <template v-slot:activator="{ on, attrs }">
          <v-btn-toggle v-model="activeFindBtn" multiple dense color="condition_btn_bg">
            <v-btn
              outlined
              color="condition_btn_bg"
              ref="gridSearchBtn"
              class="i-search-panel-button search_grid"
              style="border-radius:4px !important;"
              @click="findIconClick"
              v-bind="attrs"
              v-on="on"
            >
              <svg-icon style="color:#9BA4AC;" icon-class="search_grid" />
            </v-btn>
          </v-btn-toggle>
        </template>
        <span>통합 검색</span>
      </v-tooltip>

      <!-- <transition name="fade"> -->
      <v-text-field
        v-if="isFindOpen"
        ref="txtFindRef"
        placeholder="통합검색"
        class="i-search-panel-text-field ml-2"
        dense
        hide-details="auto"
        clearable
        @change="changeInput"
      >
        <template v-slot:append>
          <svg-icon style="height:1rem; color:#9BA4AC;" icon-class="search"></svg-icon>
        </template>
      </v-text-field>
      <!-- </transition> -->
    </v-row>
  </span>
</template>
<script>
import Baseview from '@/views/base/baseview.vue'

export default {
  extends: Baseview,
  name: 'iSearchPanel',
  props: {
    searchPanel: {
      type: Boolean,
      default: false
    }
  },
  created() {
    this.$EventBus.$on(this.$route.name + 'initSearchPanel', x => {
      this.initSearchPanel()
    })
  },
  data: function() {
    return {
      isFindOpen: false,
      name: 'iSearchPanel',
      activeFilterBtn: [],
      activeFindBtn: []
    }
  },
  methods: {
    HeaderfilterIconClick() {
      this.baseHeaderFilterIconClick()
    },
    filterIconClick() {
      this.baseFilterIconClick()
    },
    findIconClick() {
      this.isFindOpen = !this.isFindOpen
      this.baseFindIconClick('')
    },
    changeInput(value) {
      this.baseFindIconClick(value)
    },
    initSearchPanel() {
      // 그리드 찾기
      let childrenCompoent = this.$parent.$children
      let gridComponent = childrenCompoent.find(element => {
        return element.instance ? element.instance.NAME === 'dxDataGrid' : false
      })

      // 필터 초기화
      gridComponent.instance.clearFilter()
      gridComponent.instance.option('filterRow.visible', false)
      gridComponent.instance.searchByText('')
      this.isFindOpen = false
      // 버튼토글 초기화
      this.activeFilterBtn = []
      this.activeFindBtn = []
    }
  }
}
</script>
<style lang="scss" scoped>
.i-search-panel-button {
  background-color: transparent !important;
}

.i-search-panel-text-field {
  width: 180px;
  position: relative;
  left: -1px;
}
.theme--light.v-btn-toggle:not(.v-btn-toggle--group) .v-btn.v-btn {
  // border: none !important;
  // color: #214885 !important;
  // background: #e1e7f2 !important;
  // border: 1px solid #9e9e9e !important;
  border-radius: 0 !important;
}

.v-btn .v-item--active {
  background: red !important;
}

.v-btn-toggle .v-btn.v-btn.v-size--default {
  min-width: 28px;
  min-height: 28px;
}

.v-btn:not(.v-btn--round).v-size--default {
  width: 28px;
  height: 28px;
}

.fade-enter-active,
.fade-leave-active {
  transition: opacity 0.3s;
}
.fade-enter, .fade-leave-to /* .fade-leave-active below version 2.1.8 */ {
  opacity: 0;
}
.svg-icon {
  height: 0.9rem !important;
}
</style>
