<template>
  <div>
    <v-system-bar id="systemBar" v-show="IsShow" dark lights-out color="red lighten-1 tooltip">
    </v-system-bar>
  </div>
</template>
<script>
export default {
  name: 'i-system-bar',
  data: () => ({ bShow: true, error: { code: '200', message: '' } }),
  computed: {
    IsShow() {
      return this.bShow
    },
    errorMessage() {
      if (this.error.code == '200') {
        this.bShow = false
        return ''
      } else {
        this.bShow = true
        return 'code : ' + this.error.code + ', message : ' + this.error.message
      }
    }
  },
  mounted() {
    this.bShow = true
  },
  methods: {
    close() {
      this.bShow = false
    }
    // html 기존 코드
