  //       <v-icon dark>
  //         mdi-close
  //       </v-icon>
  //     </v-btn>
  //     <div class="v-system-bar v-system-bar--lights-out theme--dark red lighten-1" id="systemBar">
  //       <!-- <i aria-hidden="true" class="v-icon notranslate mdi mdi-play theme--dark"></i>
  //       <span>오류ID: -2000메세지: 조회결과가 없습니다.</span> -->
  //       <div class="spacer"></div>
  //     </div>
  //   </v-system-bar>
  // </div>
  }
}
</script>
<style scoped>
#systemBar {
  height: 0 !important;
  color: transparent;
}
</style>
