<template>
  <div class="d-flex iButtonList align-center">
    <v-btn v-if="refresh" text icon x-large color="blue darken-2" @click="clickRefresh()">
      <v-icon>
        mdi-cached
      </v-icon>
    </v-btn>
    <!-- 
    <i-button
      v-for="btn in buttonList"
      :key="`btn_${btn.id}`"
      color="btn_bg"
      :iconPre="true"
      :icon="btn.icon"
      :text="btn.text"
      :role="`${btn.id}`"
      class="ml-1 pl-2 pr-1"
      @click="clickButton(btn)"
    >
     -->
    <i-button
      v-for="btn in buttonList"
      :key="`btn_${btn.id}`"
      color="btn_bg"
      :text="$t(btn.id)"
      :role="`${btn.id}`"
      class="ml-1 px-2"
      @click="clickButton(btn)"
    >
    </i-button>
    <!-- v-card vertical ibuttonlist color&padding -->
    <v-menu v-if="usePrint" content-class="report-menu" offset-y :close-on-click="true">
      <template v-slot:activator="{ on }">
        <!-- i-button 같은 템플릿으로 한번 감쌀경우 적용이 안되어 v-btn 사용 -->
        <v-btn class=" ml-1 px-2 white--text d-flex copyBtn" elevation="0" v-on="on" color="btn_bg" height="28" outlined :role="`${printButton.id}`">
          <!-- <v-icon class="float-left" :color="fontColor"> ${{ printButton.icon }} </v-icon> -->
          <!-- <svg-icon icon-class="printer_condition" class="mr-1"></svg-icon> -->
          <div class="float-center font-weight-bold text-center mx-1" style="color: #0E1113;">
            {{ $t(printButton.id) }}
          </div>
        </v-btn>
      </template>
      <div v-for="(reportbtn, index) in reportItems" :key="`btn_${reportbtn.role}`">
        <v-divider v-if="index !== 0" style="" />
        <v-btn width="100%" depressed text class="px-3" @click="clickButton(reportbtn)">
          {{ $t(reportbtn.title) }}
        </v-btn>
      </div>
    </v-menu>
    <!-- 위험성평가 사전준비 샘플 선택 메뉴  -->
    <v-menu v-if="useRiskSampleType" content-class="report-menu" offset-y :close-on-click="true">
      <template v-slot:activator="{ on }">
        <!-- i-button 같은 템플릿으로 한번 감쌀경우 적용이 안되어 v-btn 사용 -->
        <v-btn
          class=" ml-1 px-6 white--text d-flex copyBtn"
          elevation="0"
          outlined
          v-on="on"
          color="btn_bg"
          height="28"
          :role="`${riskSampleTypeButton.id}`"
        >
          <!-- <svg-icon icon-class="sample_condition"></svg-icon> -->
          <!-- <v-icon class="float-left"> ${{ riskSampleTypeButton.icon }} </v-icon> -->

          <div class="float-center mx-1 font-weight-bold" style="color: #0E1113;">
            {{ $t(riskSampleTypeButton.id) }}
          </div>
        </v-btn>
      </template>
      <div v-for="(riskSampeTypebtn, index) in riskSampleTypeItems" :key="`btn_${riskSampeTypebtn.role}`">
        <v-divider v-if="index !== 0" style="" />
        <v-btn width="100%" depressed text class="px-3 ml-1 font-weight-bold" @click="clickButton(riskSampeTypebtn)">
          {{ $t(riskSampeTypebtn.title) }}
        </v-btn>
      </div>
    </v-menu>
  </div>
</template>

<script>
import iButton from './iButton.vue'

export default {
  components: { iButton },
  name: 'i-button-list',
  props: {
    useBtnList: {
      type: Array,
      default: () => ['']
    },
    refresh: {
      type: Boolean,
      default: false
    },
    reportItems: {
      type: Array,
      default: () => [
        { role: 'pptx', title: 'PPT' },
        { role: 'pdf', title: 'PDF' },
        { role: 'docx', title: 'DOCX' },
        // { role: 'html', title: 'WEB'},
        { role: 'xls', title: 'EXCEL' }
      ]
    }
  },
  computed: {
    computedFontStyle() {
      let fontColor = this.fontColor
      if (this.disabled) {
        fontColor = 'content'
      }
      return {
        color: '#000',
        'font-size': this.fontSize + 'px',
        'letter-spacing': '0.5px',
        'font-weight': this.fontWeight,
        'line-height': 1.8
      }
    }
  },
  data() {
    return {
      // icon은 assets/theme/vuetify/ 적용되고 있는 esg0x.js 참조
      buttonList: [
        { id: 'btnSearch', text: '조회', icon: 'search_condition' },
        { id: 'btnSampleCopy', text: '샘플불러오기', icon: 'sample_condition' },
        { id: 'btnAdd', text: '추가', icon: 'add_condition' },
        { id: 'btnSave', text: '저장', icon: 'save_condition' },
        { id: 'btnEdit', text: '편집', icon: 'reload' },
        { id: 'btnTempSave', text: '임시저장', icon: 'save_condition' },
        { id: 'btnDelete', text: '삭제', icon: 'delete_condition' },
        { id: 'btnPrint', text: '출력', icon: 'print' },
        { id: 'btnExcel', text: '출력', icon: 'print' },
        { id: 'btnClose', text: '닫기', icon: 'close' },
        { id: 'btnConfirm', text: '확인', icon: 'confirm' },       
        { id: 'btnCapture', text: '캡처', icon: 'camera' },
        { id: 'btnApply', text: '적용', icon: 'apply' },
        { id: 'btnCopy', text: '복사', icon: 'copy' },
        { id: 'btnNew', text: '신규', icon: 'newfile' },
        { id: 'btnReConfirm', text: '제정/개정', icon: 'reconfirm' },
        { id: 'btnReduce', text: '위험성평가 결과 등록', icon: 'add_condition' },
        { id: 'btnUpload', text: '업로드', icon: 'upload' },
        { id: 'btnSampleEquipment', text: '샘플설비유형', icon: 'sampleE_condition' }        
      ],
      progCd: this.$route.meta.proc_cd,
      menuId: this.$route.params == undefined ? '' : this.$route.params.selMenuid,
      savAh: '', //저장
      schAh: '', //조회
      delAh: '', //삭제
      exlAh: '', //엑셀출력(프린트)
      fn1Ah: '', //기능1
      fn2Ah: '', //기능2
      fn3Ah: '', //기능3
      usePrint: false,
      printButton: null,
      riskSampleTypeButton: null,
      useRiskSampleType: false,
      riskSampleTypeItems: [
        { role: '3b3', title: '3*3' },
        { role: '5b4', title: '5*4' }
      ],
      // reportItems: [
      //   { role: 'pptx', title: 'PPT' },
      //   { role: 'pdf', title: 'PDF' },
      //   { role: 'docx', title: 'DOCX' },
      //   // { role: 'html', title: 'WEB'},
      //   { role: 'xls', title: 'EXCEL' }
      // ],
      fontColor: '#000'
    }
  },
  created() {
    // useBtnList에서 받은 id로 필터링
    this.buttonList = this.buttonList.filter(btn => {
      return this.useBtnList.includes(btn.id)
    })
    //console.log(this.buttonList)
  },
  mounted() {
    this.getAuthority()
    this.printSetting()
    this.riskSampleTypeSetting()
  },
  methods: {
    clickButton(targetButton) {
      this.$emit('btnClick', targetButton)
    },
    clickRefresh() {
      this.$emit('btnRefreshClick')
    },
    //각 메뉴별 조회, 추가, 저장, 삭제 정보 조회
    getAuthority() {
      // 조회 api
      // 사용자권한메뉴조회

      // 20240719 myAuthGrps session storage 사용 중지, state 사용
      // 로그인 시 권한 정보를 state에 저장하고, 이 저장된 정보를 불러와 버튼 권한을 부여한다.
      if (this.$store.state.menu.myAuthGrps) {
        let authGrps = this.$store.state.menu.myAuthGrps.find(x => x.progCd == this.progCd)

        // console.log(authGrps)
        if (authGrps != null) {
          this.schAh = authGrps.schAh
          this.savAh = authGrps.savAh
          this.delAh = authGrps.delAh
          this.exlAh = authGrps.exlAh
        }

        //버튼권한별 View
        let authButtonList = this.buttonList.filter(btn => {
          //console.log(store.state.user)
          if (
            (btn.id == 'btnSearch' && this.schAh == 'Y') ||
            (btn.id == 'btnAdd' && this.savAh == 'Y') ||
            (btn.id == 'btnSave' && this.savAh == 'Y') ||
            (btn.id == 'btnTempSave' && this.savAh == 'Y') ||
            (btn.id == 'btnDelete' && this.delAh == 'Y') ||
            (btn.id == 'btnPrint' && this.exlAh == 'Y') ||
            (btn.id == 'btnExcel' && this.exlAh == 'Y') ||
            (btn.id == 'btnConfirm' && this.savAh == 'Y') ||
            (btn.id == 'btnApply' && this.savAh == 'Y') ||            
            (btn.id == 'btnEdit' && this.savAh == 'Y') ||
            (btn.id == 'btnCopy' && this.savAh == 'Y') ||
            (btn.id == 'btnNew' && this.savAh == 'Y') ||
            (btn.id == 'btnReConfirm' && this.savAh == 'Y') ||
            (btn.id == 'btnSampleCopy' && this.savAh == 'Y') ||
            (btn.id == 'btnSampleEquipment' && this.savAh == 'Y') ||
            (btn.id == 'btnReduce' && this.savAh == 'Y') ||
            (btn.id == 'btnUpload' && this.savAh == 'Y')             
          ) {
            return this.useBtnList.includes(btn.id)
          }
        })
        //console.log(authButtonList)
        this.buttonList = authButtonList
      }
    },
    //위험성평가 샘플 불러오기 타입 설정
    riskSampleTypeSetting() {
      let findIndex = this.buttonList.findIndex(element => element.id === 'btnSampleCopy')
      this.buttonList
      if (findIndex > -1) {
        this.useRiskSampleType = true
        this.riskSampleTypeButton = this.buttonList.find(element => element.id === 'btnSampleCopy')
        this.riskSampleTypeItems.forEach(element => {
          Object.assign(element, this.riskSampleTypeButton)
        })
        this.buttonList = this.buttonList.filter(element => element.id !== 'btnSampleCopy')
      }
    },
    // 레포트용 출력 설정
    printSetting() {
      let findIndex = this.buttonList.findIndex(element => element.id === 'btnPrint')
      this.buttonList
      if (findIndex > -1) {
        this.usePrint = true
        this.printButton = this.buttonList.find(element => element.id === 'btnPrint')
        // console.log("printButton", this.printButton)
        this.reportItems.forEach(element => {
          Object.assign(element, this.printButton)
        })
        this.buttonList = this.buttonList.filter(element => element.id !== 'btnPrint')
      }
    }
  }
}
</script>

<style lang="scss" scoped>
// .v-btn {
//   background: #ffffff;
// }

.v-btn.v-size--default {
  font-size: 0.7rem;
}

// .report-menu {
//   z-index: 10 !important;
// }

.v-icon.v-icon {
  font-size: 1.2rem !important;
  padding-right: 4px;
  padding-top: 3px;
}
</style>
