<template>
  <v-card fill-height rounded>
    <v-card-title class="font-weight-bold card_title--text text-lg-h6 text-sm-h5 body-1 pa-0 pl-1">
      <div>
        {{ $t(headerTitle) }}
        <v-icon class="pb-1" color="grey lighten-1">{{ deviceArray[device] }}</v-icon>
      </div>
      <i-search-panel :searchPanel="searchPanel"></i-search-panel>
      <v-spacer v-if="useSpacer" />
      <div v-if="IsUseInnerAddition" class="additionCss d-flex align-center justify-space-between ma-0">
        <slot name="innerAddition"> </slot>
      </div>
      <i-button-list :reportItems="reportItems" :useBtnList="useBtnList" :refresh="refresh" @btnRefreshClick="clickRefresh" @btnClick="clickButton" />
    </v-card-title>
    <div v-if="IsUseAddition" class="additionCss d-flex align-center justify-space-between ma-0 my-2"><slot name="addition"> </slot></div>
    <v-card-text class="pa-0 pt-1">
      <i-system-bar></i-system-bar>
      <slot name="body">
        {{}}
      </slot>
    </v-card-text>
  </v-card>
</template>

<script>
import iButtonList from './iButtonList.vue'
import iSearchPanel from '@/components/common/iSearchPanel.vue'
import systemBar from '@/components/common/systemBar.vue'

export default {
  name: 'i-card-vertical',
  components: {
    'i-system-bar': systemBar,
    iButtonList,
    iSearchPanel
  },
  props: {
    headerTitle: {
      type: String,
      default: '제목'
    },
    color: {
      type: String,
      default: 'card_bg'
    },
    divider: {
      type: Boolean,
      default: false
    },
    // 버튼 리스트
    useBtnList: {
      type: Array,
      default: () => ['']
    },
    refresh: {
      type: Boolean,
      default: false
    },
    IsUseAddition: {
      type: Boolean,
      default: false
    },
    IsUseInnerAddition: {
      type: Boolean,
      default: false
    },
    reportItems: {
      type: Array,
      default: () => [
        { role: 'pptx', title: 'PPT' },
        { role: 'pdf', title: 'PDF' },
        { role: 'docx', title: 'DOCX' },
        { role: 'xls', title: 'EXCEL' }
      ]
    },
    device: {
      type: String,
      default: 'none'
    },
    //headerTitle 뒤 공백 제거(false), default는 공백
    //상세 그리드의 경우, 조회/저장/삭제 등 버튼이 headerTitle 뒤에 붙어야됨
    useSpacer: {
      type: Boolean,
      default: true
    }
  },
  data() {
    return {
      searchPanel: false,
      deviceArray: {
        web: 'mdi-monitor',
        multi: 'mdi-monitor-cellphone',
        none: ''
      }
    }
  },
  mounted() {
    this.foundGridComponent()
  },
  methods: {
    // 버튼 클릭 시 각 id별로 이벤트생성
    clickButton(targetButton) {
      this.$emit(targetButton.id, targetButton.role)
    },
    clickRefresh() {
      this.$emit('btnRefreshClick')
    },
    foundGridComponent() {
      // 그리드 찾기
      let childrenCompoent = this.$children[0].$children
      let gridComponent = childrenCompoent.find(element => {
        return element.instance ? element.instance.NAME === 'dxDataGrid' : false
      })
      this.searchPanel = !!gridComponent
    }
  }
}
</script>

<style lang="scss" scoped>
.additionCss {
  font-size: 0.75rem;
  font-weight: bold;
  color: #171956;
  .infoBg {
    background: #f5f7fb;
  }
}
</style>
