<template>
  <v-btn
    class="d-flex justify-center align-center conditionBtn"
    :color="backgrounColor"
    style="border-radius: 4px !important;"
    :style="`height: ${height};`"
    :fontWeight="fontWeight"
    :height="height"
    :max-height="height"
    :min-height="height"
    :disabled="disabled"
    elevation="0"
    outlined
    @click="click"
  >
    <!-- mdi icon 대신 svg icon 사용 -->
    <!-- <svg-icon v-if="iconPre === true" :icon-class="icon" :size="iconSize" :color="fontColor" class="mr-1"></svg-icon> -->
    <!-- <v-icon v-if="iconPre === true" class="float-left" :size="iconSize" :color="fontColor"> ${{ icon }} </v-icon> -->

    <slot></slot>

    <div class="float-center font-weight-bold text-center mx-1" :style="computedFontStyle">
      {{ text }}
    </div>

    <!-- <v-icon v-if="iconOnly === true" class="mr-2" :size="iconSize" :color="fontColor">
      {{ icon }}
    </v-icon> -->
  </v-btn>
</template>
<script>
export default {
  name: 'i-button',

  props: {
    //버튼 배경 색상
    backgrounColor: { type: String, default: 'btn_bg' },
    //버튼 내 문자열
    text: {
      type: String,
      default: () => {
        return ''
      }
    },

    //버튼 내 문자열 색상
    fontColor: { default: '#2A30A4' },

    //버튼 내 문자열 두께
    fontWeight: { type: String, default: 'medium' },

    //버튼 테두리 색상
    borderColor: { type: String },

    //버튼 너비 값
    // width: {
    //   type: String,
    //   default: function() {
    //     return '80px'
    //   }
    // },

    //버튼 높이 값
    height: {
      type: String,
      default: function() {
        return '28px'
      }
    },

    //문자열 폰트 크기
    fontSize: { default: '13px' },

    //문자열 disabled 처리
    disabled: {
      type: Boolean,
      default: () => {
        return false
      }
    },

    //icon
    icon: {
      type: String,
      default: function() {
        return ''
      }
    },

    //아이콘 삽입
    iconPre: {
      type: Boolean,
      default: () => {
        return false
      }
    },

    //아이콘만 표기
    iconOnly: {
      type: Boolean,
      default: () => {
        return false
      }
    },

    //아이콘 크기
    iconSize: { type: String }
  },

  computed: {
    computedFontStyle() {
      let fontColor = this.fontColor
      if (this.disabled) {
        fontColor = 'content'
      }
      return {
        color: '#0E1113',
        'font-size': this.fontSize + 'px',
        'letter-spacing': '0.5px',
        'font-weight': this.fontWeight,
        'line-height': 1.8
      }
    }
  },

  methods: {
    click() {
      this.$emit('click')
    }
  }
}
</script>
<style lang="scss" scoped>
// .v-btn {
//   background: #ffffff;
// }

.v-btn.v-size--default {
  font-size: 0.7rem;
}

.v-icon.v-icon {
  font-size: 1.2rem !important;
  padding-right: 4px;
  padding-top: 3px;
}

.svg-icon {
  height: 1rem !important;
}
</style>
